const { ethers } = require('hardhat'); async function main() { const [signer] = await ethers.getSigners(); console.log('Signer:', signer.address); const MockERC20 = await ethers.getContractFactory('MockERC20'); const usdc = MockERC20.attach('0x2BC080CA5b67a57739972e6B4B051F64D082A48c'); const bal = await usdc.balanceOf(signer.address); console.log('USDC Balance:', bal.toString()); } main().catch(console.error);
